module simple_alu(
    input      [7:0] obf_a      ,
    input      [7:0] b      ,
    input      [1:0] ctrl   ,

    output reg [7:0] result
);

always @(*) begin
    case(ctrl)
        2'b00: result = obf_a + b;
        2'b01: result = obf_a - b;
        2'b10: result = obf_a & b;
        2'b11: result = obf_a | b;
        default: result = 8'b0;
    endcase
end

endmodule
